(window.webpackJsonp=window.webpackJsonp||[]).push([[900],{1195:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> PredictTheWinner = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n  <span class=\\"hljs-keyword\\">return</span> calc(<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>,nums.length<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-literal\\">true</span>)\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">calc</span>(<span class=\\"hljs-params\\">p1,p2,lo,hi,turn</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(lo&gt;hi){\\n      <span class=\\"hljs-keyword\\">if</span>(turn)<span class=\\"hljs-keyword\\">return</span> p1&gt;=p2\\n      <span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">return</span> p2&gt;p1\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-literal\\">false</span>\\n    <span class=\\"hljs-keyword\\">if</span>(turn){\\n      res=!calc(p1+nums[lo],p2,lo+<span class=\\"hljs-number\\">1</span>,hi,!turn) || !calc(p1+nums[hi],p2,lo,hi<span class=\\"hljs-number\\">-1</span>,!turn)\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      res=!calc(p1,p2+nums[lo],lo+<span class=\\"hljs-number\\">1</span>,hi,!turn) || !calc(p1,p2+nums[hi],lo,hi<span class=\\"hljs-number\\">-1</span>,!turn)\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n  }\\n};\\n</code></pre>\\n","<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">PredictTheWinner</span><span class=\\"hljs-params\\">(self, nums)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type nums: List[int]\\n        :rtype: bool\\n        \\"\\"\\"</span>\\n        n=len(nums)\\n        dp=[[<span class=\\"hljs-number\\">0</span>]*n <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(n)]\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(n):\\n          dp[i][i]=nums[i]\\n        \\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,n):\\n          <span class=\\"hljs-keyword\\">for</span> j <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">0</span>,n-i):\\n            k=j+i\\n            dp[j][k]=max(nums[j]-dp[j+<span class=\\"hljs-number\\">1</span>][k],nums[k]-dp[j][k<span class=\\"hljs-number\\">-1</span>])\\n        <span class=\\"hljs-keyword\\">return</span> dp[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">-1</span>]&gt;=<span class=\\"hljs-number\\">0</span>\\n</code></pre>\\n"],"titleSlug":"predict-the-winner","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u8868\u793a\u5206\u6570\u7684\u975e\u8d1f\u6574\u6570\u6570\u7ec4\u3002 \u73a9\u5bb6 1 \u4ece\u6570\u7ec4\u4efb\u610f\u4e00\u7aef\u62ff\u53d6\u4e00\u4e2a\u5206\u6570\uff0c\u968f\u540e\u73a9\u5bb6 2 \u7ee7\u7eed\u4ece\u5269\u4f59\u6570\u7ec4\u4efb\u610f\u4e00\u7aef\u62ff\u53d6\u5206\u6570\uff0c\u7136\u540e\u73a9\u5bb6 1 \u62ff\uff0c&hellip;&hellip; \u3002\u6bcf\u6b21\u4e00\u4e2a\u73a9\u5bb6\u53ea\u80fd\u62ff\u53d6\u4e00\u4e2a\u5206\u6570\uff0c\u5206\u6570\u88ab\u62ff\u53d6\u4e4b\u540e\u4e0d\u518d\u53ef\u53d6\u3002\u76f4\u5230\u6ca1\u6709\u5269\u4f59\u5206\u6570\u53ef\u53d6\u65f6\u6e38\u620f\u7ed3\u675f\u3002\u6700\u7ec8\u83b7\u5f97\u5206\u6570\u603b\u548c\u6700\u591a\u7684\u73a9\u5bb6\u83b7\u80dc\u3002</p>\\n\\n<p>\u7ed9\u5b9a\u4e00\u4e2a\u8868\u793a\u5206\u6570\u7684\u6570\u7ec4\uff0c\u9884\u6d4b\u73a9\u5bb61\u662f\u5426\u4f1a\u6210\u4e3a\u8d62\u5bb6\u3002\u4f60\u53ef\u4ee5\u5047\u8bbe\u6bcf\u4e2a\u73a9\u5bb6\u7684\u73a9\u6cd5\u90fd\u4f1a\u4f7f\u4ed6\u7684\u5206\u6570\u6700\u5927\u5316\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[1, 5, 2]\\n<strong>\u8f93\u51fa\uff1a</strong>False\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e00\u5f00\u59cb\uff0c\u73a9\u5bb61\u53ef\u4ee5\u4ece1\u548c2\u4e2d\u8fdb\u884c\u9009\u62e9\u3002\\n\u5982\u679c\u4ed6\u9009\u62e9 2\uff08\u6216\u8005 1 \uff09\uff0c\u90a3\u4e48\u73a9\u5bb6 2 \u53ef\u4ee5\u4ece 1\uff08\u6216\u8005 2 \uff09\u548c 5 \u4e2d\u8fdb\u884c\u9009\u62e9\u3002\u5982\u679c\u73a9\u5bb6 2 \u9009\u62e9\u4e86 5 \uff0c\u90a3\u4e48\u73a9\u5bb6 1 \u5219\u53ea\u5269\u4e0b 1\uff08\u6216\u8005 2 \uff09\u53ef\u9009\u3002\\n\u6240\u4ee5\uff0c\u73a9\u5bb6 1 \u7684\u6700\u7ec8\u5206\u6570\u4e3a 1 + 2 = 3\uff0c\u800c\u73a9\u5bb6 2 \u4e3a 5 \u3002\\n\u56e0\u6b64\uff0c\u73a9\u5bb6 1 \u6c38\u8fdc\u4e0d\u4f1a\u6210\u4e3a\u8d62\u5bb6\uff0c\u8fd4\u56de False \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[1, 5, 233, 7]\\n<strong>\u8f93\u51fa\uff1a</strong>True\\n<strong>\u89e3\u91ca\uff1a</strong>\u73a9\u5bb6 1 \u4e00\u5f00\u59cb\u9009\u62e9 1 \u3002\u7136\u540e\u73a9\u5bb6 2 \u5fc5\u987b\u4ece 5 \u548c 7 \u4e2d\u8fdb\u884c\u9009\u62e9\u3002\u65e0\u8bba\u73a9\u5bb6 2 \u9009\u62e9\u4e86\u54ea\u4e2a\uff0c\u73a9\u5bb6 1 \u90fd\u53ef\u4ee5\u9009\u62e9 233 \u3002\\n     \u6700\u7ec8\uff0c\u73a9\u5bb6 1\uff08234 \u5206\uff09\u6bd4\u73a9\u5bb6 2\uff0812 \u5206\uff09\u83b7\u5f97\u66f4\u591a\u7684\u5206\u6570\uff0c\u6240\u4ee5\u8fd4\u56de True\uff0c\u8868\u793a\u73a9\u5bb6 1 \u53ef\u4ee5\u6210\u4e3a\u8d62\u5bb6\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>1 &lt;= \u7ed9\u5b9a\u7684\u6570\u7ec4\u957f\u5ea6&nbsp;&lt;= 20.</li>\\n\\t<li>\u6570\u7ec4\u91cc\u6240\u6709\u5206\u6570\u90fd\u4e3a\u975e\u8d1f\u6570\u4e14\u4e0d\u4f1a\u5927\u4e8e 10000000 \u3002</li>\\n\\t<li>\u5982\u679c\u6700\u7ec8\u4e24\u4e2a\u73a9\u5bb6\u7684\u5206\u6570\u76f8\u7b49\uff0c\u90a3\u4e48\u73a9\u5bb6 1 \u4ecd\u4e3a\u8d62\u5bb6\u3002</li>\\n</ul>\\n","title":"486. \u9884\u6d4b\u8d62\u5bb6","relatedTags":["\u6781\u5c0f\u5316\u6781\u5927","\u52a8\u6001\u89c4\u5212"],"difficult":"Middle","lang":["javascript","python"],"uniqueID":"486"}')}}]);